import ldap

def search_user_in_ldap(ldap_server, base_dn, username):
    # Connect to the LDAP server
    l = ldap.initialize(ldap_server)
    
    try:
        # Bind with a user that has permission to search the directory
        l.simple_bind_s('cn=admin,dc=example,dc=com', 'admin_password')
        
        # Define the search filter
        search_filter = f'uid={username}'
        
        # Search for the user
        result_id = l.search(base_dn, ldap.SCOPE_SUBTREE, search_filter)
        
        # Retrieve and return the search results
        result_set = []
        while 1:
            result_type, result_data = l.result(result_id, 0)
            if (result_data == []):
                break
            else:
                if result_type == ldap.RES_SEARCH_ENTRY:
                    result_set.append(result_data)
        
        return result_set
    
    except ldap.LDAPError as e:
        print(f"LDAP error occurred: {e}")
    
    finally:
        l.unbind_s()

